// BottomNav laut CLAUDE.md §5: 4 Items mit Emoji + Label, BG var(--red),
// aktiv opacity:1, inaktiv opacity:0.6.
// Routing-Targets sind die canonical-Pfade aus CLAUDE.md §10.

import { NavLink } from 'react-router-dom'

type Item = {
  to: string
  emoji: string
  label: string
  // matchPaths gibt zusätzliche Pfad-Präfixe an, unter denen das Item als aktiv gilt
  // (z.B. /learn/* matched alle Spielmodi unter LERNEN).
  matchPrefix?: string
}

const items: Item[] = [
  { to: '/home',    emoji: '🏠', label: 'HOME' },
  { to: '/learn',   emoji: '📖', label: 'LERNEN', matchPrefix: '/learn' },
  { to: '/stats',   emoji: '📊', label: 'STATS' },
  { to: '/profile', emoji: '👤', label: 'PROFIL', matchPrefix: '/profile' }
]

export function BottomNav() {
  return (
    <nav
      style={{
        position: 'fixed',
        bottom: 0,
        left: 0,
        right: 0,
        display: 'flex',
        background: 'var(--red)',
        paddingBottom: 'env(safe-area-inset-bottom, 0px)',
        boxShadow: '0 -2px 12px rgba(0, 0, 0, 0.15)',
        zIndex: 50
      }}
    >
      {items.map((item) => (
        <NavLink
          key={item.to}
          to={item.to}
          end={!item.matchPrefix}
          style={({ isActive }) => ({
            flex: 1,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '10px 4px 12px',
            color: 'var(--cream)',
            opacity: isActive ? 1 : 0.6,
            textDecoration: 'none',
            transition: 'opacity 120ms ease-out'
          })}
        >
          <span style={{ fontSize: 22, lineHeight: 1 }} aria-hidden="true">
            {item.emoji}
          </span>
          <span
            style={{
              fontSize: 8,
              letterSpacing: '0.5px',
              marginTop: 4,
              fontWeight: 600
            }}
          >
            {item.label}
          </span>
        </NavLink>
      ))}
    </nav>
  )
}
